import{_ as a,o as i,c as e,a9 as r}from"./chunks/framework.STMWz9Nm.js";const c=JSON.parse('{"title":"MySQL学习","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/07-MySQL学习/07-MySQL学习.md","filePath":"语言/java/07-MySQL学习/07-MySQL学习.md","lastUpdated":1777106511000}'),t={name:"语言/java/07-MySQL学习/07-MySQL学习.md"};function h(n,l,o,d,s,_){return i(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="mysql学习" tabindex="-1">MySQL学习 <a class="header-anchor" href="#mysql学习" aria-label="Permalink to “MySQL学习”">​</a></h1><p>MySQL 是 Java 后端开发里最核心的基础设施之一。<br> 学习 MySQL 不能停留在“会写增删改查”，更重要的是理解索引、事务、锁、执行计划、复制与高可用这些关键机制。</p><h2 id="专题目录" tabindex="-1">专题目录 <a class="header-anchor" href="#专题目录" aria-label="Permalink to “专题目录”">​</a></h2><ul><li><a href="./01-MySQL架构与存储引擎.html">01-MySQL架构与存储引擎</a></li><li><a href="./02-索引设计.html">02-索引设计</a></li><li><a href="./03-事务与隔离级别.html">03-事务与隔离级别</a></li><li><a href="./04-SQL优化与执行计划.html">04-SQL优化与执行计划</a></li><li><a href="./05-锁与并发控制.html">05-锁与并发控制</a></li><li><a href="./06-主从复制与高可用.html">06-主从复制与高可用</a></li></ul><h2 id="_1-学习定位" tabindex="-1">1. 学习定位 <a class="header-anchor" href="#_1-学习定位" aria-label="Permalink to “1. 学习定位”">​</a></h2><p>这一组内容面向 Java 后端开发里的数据库核心能力。<br> 目标不是成为 DBA，而是让你具备这些能力：</p><ul><li>看懂 MySQL 执行链路</li><li>设计合理索引</li><li>理解事务与锁问题</li><li>会分析慢 SQL</li><li>能和线上排障结合起来</li></ul><h2 id="_2-学习重点" tabindex="-1">2. 学习重点 <a class="header-anchor" href="#_2-学习重点" aria-label="Permalink to “2. 学习重点”">​</a></h2><ul><li>理解 InnoDB 为什么成为主流</li><li>理解索引如何影响查询路径</li><li>理解事务与锁如何保证一致性</li><li>理解执行计划如何帮助定位慢 SQL</li><li>理解复制和高可用如何支撑线上系统</li></ul><h2 id="_3-建议顺序" tabindex="-1">3. 建议顺序 <a class="header-anchor" href="#_3-建议顺序" aria-label="Permalink to “3. 建议顺序”">​</a></h2><ol><li>MySQL架构与存储引擎</li><li>索引设计</li><li>事务与隔离级别</li><li>SQL优化与执行计划</li><li>锁与并发控制</li><li>主从复制与高可用</li></ol><h2 id="_4-阶段产出" tabindex="-1">4. 阶段产出 <a class="header-anchor" href="#_4-阶段产出" aria-label="Permalink to “4. 阶段产出”">​</a></h2><ul><li>一份索引设计总结</li><li>一份事务与锁问题排查笔记</li><li>一份 SQL 优化案例复盘</li><li>一份主从复制与高可用理解图</li></ul><h2 id="_5-自测标准" tabindex="-1">5. 自测标准 <a class="header-anchor" href="#_5-自测标准" aria-label="Permalink to “5. 自测标准”">​</a></h2><ul><li>能看懂一条 SQL 为什么走某个索引</li><li>能解释事务隔离级别和锁的关系</li><li>能说清 MySQL 在生产环境里如何做高可用</li><li>能从执行计划里识别明显性能风险</li></ul>',15)])])}const m=a(t,[["render",h]]);export{c as __pageData,m as default};
